// ============================================================================
// URL SETUP (SEPARATED FROM REST OF FILE INTENTIONALLY)
// ============================================================================

/** Central asset registry — keep all data URLs here */
const ASSETS = {
    // PNGs
    ICON_32: 'data:image/png;base64,',
    ICON_128: 'data:image/png;base64,',
    ICON_256: 'data:image/png;base64,',

    // Favicon ICO
    FAVICON: 'data:image/x-icon;base64,'
};

/** Helper: set an attribute on all matches to a given asset key */
function setAsset(selector, attr, assetKey) {
    const val = ASSETS[assetKey];
    if (!val) return console.warn('Missing asset', assetKey);
    document.querySelectorAll(selector).forEach(el => el.setAttribute(attr, val));
}

/** Wire up on DOMContentLoaded so elements exist */
document.addEventListener('DOMContentLoaded', () => {
    // 1) Header logo <img>
    setAsset('.logo', 'src', 'ICON_128'); // or a different size if you want

    // 2) Favicons & app icons (<link> tags). You currently have these:

    // Update the existing link elements in-place (safer than creating new ones)
    setAsset('link[rel="icon"][type="image/x-icon"]', 'href', 'FAVICON');
    setAsset('link[rel="icon"][sizes="32x32"]', 'href', 'ICON_32');
    setAsset('link[rel="icon"][sizes="128x128"]', 'href', 'ICON_128');
    setAsset('link[rel="icon"][sizes="256x256"]', 'href', 'ICON_256');
    setAsset('link[rel="apple-touch-icon"]', 'href', 'ICON_256'); // reuse 256 for touch icon
});

document.addEventListener("DOMContentLoaded", () => {
    document.getElementById("onboarding-logo").src = ASSETS.ICON_128;
})